/**
 * @method 
 * @name f_Save 
 * @description 저장
 */
scwin.f_Save = async function () {
  if (dma_HouseFreightInfo.getModifiedIndex().length > 0 || ds_BuyingFreightInfo.getModifiedIndex().length > 0 || ds_SellingFreightInfo.getModifiedIndex().length > 0 || ds_PartnerFreightInfo.getModifiedIndex().length > 0) {
    dma_HouseFreightInfo.set('kcomcd', hd_kcomcd.getValue());
    dma_HouseFreightInfo.set('blno', ed_blno.getValue());
    const reqChk = await scwin.f_ReqFieldChk();
    if (!reqChk) return;
    const jobClose = await scwin.f_JobCloseYn();
    if (!jobClose) return;
    if (reqChk && jobClose) {
      scwin.actionFlag = 'Save';

      // UserStatus-JSP 화면에 Head 와 Body(그리드)가 있을경우 Body가 변경 될 경우,
      // 무조건 Head도 서버 로 전송 해서 업데이트 하기 위해서 사용 됨
      if (dma_HouseFreightInfo.get('status') == 'U') {
        dma_HouseFreightInfo.set('status', ''); // status
      } else {
        dma_HouseFreightInfo.set('status', 'U'); // status
      }
      ;

      //저장하시겠습니까?
      const retConfirm = await $c.win.confirm($p, E_MSG_CM_CRM_001);
      if (!retConfirm) return;
      scwin.v_linkcheck = '';
      await scwin.submitExcute(sbm_Save);
    }
  } else {
    $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_001, ['Master Freight Info']); //@은(는) 변경된 사항이 없습니다.
  }
  ;
};

/**
 * @method 
 * @name f_postDtChk 
 * @description
 */
scwin.f_postDtChk = async function (odrNo, sellSeq, kcomcd, seaAirCls, blNo, mhno) {
  sbm_postDtDataSet.action = '/cm.zz.RetrieveCommonPopupCMD.do?sysCd=ilCommonEBC' + '&queryId=' + 'retrievePostDt' + '&param1=' + odrNo + '&param2=' + sellSeq + '&param3=' + scwin.kcomcd + '&param4=' + seaAirCls + '&param5=' + blNo + '&param6=' + mhno + '&param7=' + '' + '&param8=' + '' + '&param9=' + '' + '&param10=' + '' + '&param11=' + '' + '&param12=' + '' + '&param13=' + '' + '&param14=' + '';
  await scwin.submitExcute(sbm_postDtDataSet);
};

/**
 * @method 
 * @name f_ReqFieldChk 
 * @description 유효성검사
 */
scwin.f_ReqFieldChk = async function () {
  if (ica_exdt.getValue() == '') {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ['Ex-Rate Date']); // @은(는) 필수 입력 항목입니다.
    ica_exdt.focus();
    return false;
  }
  ;
  if (ed_rate.getValue() == '' || ed_rate.getValue() == '0') {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ['Ex-Rate']); // @은(는) 필수 입력 항목입니다.
    ed_rate.focus();
    return false;
  }
  ;
  if (ed_exrate.getValue() == '' || ed_exrate.getValue() == '0') {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ['US Ex-Rate']); // @은(는) 필수 입력 항목입니다.
    ed_exrate.focus();
    return false;
  }
  ;
  let rowCnt, rowData, cntNum;

  // Buying
  rowCnt = ds_BuyingFreightInfo.getRowCount();
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_BuyingFreightInfo.getRowJSON(i);
    cntNum = i + 1;
    if (rowData['pchsTyp'] == '3' && rowData['sellDeptCd'] == '') {
      await $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_002, ['Inner Department']); //@는 필수입력항목입니다.
      gr_BuyingFreightInfo.setFocusedCell(i, 'sellDeptCd');
      scwin.f_selectTabMenu(2);
      return false;
    }
    ;
    if (rowData['vatYn'] == 0 && rowData['vat'] > 0) {
      await $c.win.alert($p, '영세코드와 부가세 금액은 함께 입력될 수 없습니다. \n' + 'Buying List ' + cntNum + '번째 데이터를 확인하세요.');
      gr_BuyingFreightInfo.setFocusedCell(i, 0);
      scwin.f_selectTabMenu(2);
      return false;
    }
    ;
    if (rowData['pchsAmt'] == '0') {
      await $c.win.alert($p, 'Amount(W) 금액이 0입니다. \n' + 'Buying List ' + cntNum + '번째 데이터를 확인하세요.');
      gr_BuyingFreightInfo.setFocusedCell(i, 'pchsAmt');
      scwin.f_selectTabMenu(2);
      return false;
    }
    ;

    //삭제 시 내부거래 체크
    if (ds_BuyingFreightInfo.getRowStatusValue(i) == 2) {
      scwin.f_postDtChk(rowData['odrNo'], rowData['pchsSeq'], rowData['kcomcd'], rowData['seaAirCls'], rowData['blNo'], rowData['mhno']);
      let isPostDt = ds_postDtDataSet.getCellData(0, 'col1');
      if (isPostDt != '') {
        $c.win.alert($p, '내부거래 확정 건 입니다. \n' + 'buying List ' + cntNum + '번째 데이터를 확인하세요.');
        return false;
      }
      ;
    }
    ;
  }
  ;

  // Selling
  rowCnt = ds_SellingFreightInfo.getRowCount();
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_SellingFreightInfo.getRowJSON(i);
    cntNum = i + 1;
    if (rowData['vatYn'] == 0 && rowData['vatAmt'] > 0) {
      $c.win.alert($p, '영세코드와 부가세 금액은 함께 입력될 수 없습니다. \n' + 'Selling List ' + cntNum + '번째 데이터를 확인하세요.');
      gr_SellingFreightInfo.setFocusedCell(i, 0);
      scwin.f_selectTabMenu(0);
      return false;
    }
    ;
    if (rowData['vatYn'] == 1 && Math.abs(Math.round(rowData['sellAmt']) * 0.1 - rowData['vatAmt']) > 1) {
      $c.win.alert($p, 'VAT 금액은 Amount(W)금액의 10%입니다. \n' + 'Selling List ' + cntNum + '번째 금액을 확인하세요.');
      gr_SellingFreightInfo.setFocusedCell(i, 'vatAmt');
      return false;
    }
    ;
    if (rowData['sellAmt'] == '0') {
      $c.win.alert($p, 'Amount(W) 금액이 0입니다. \n' + 'Selling List ' + cntNum + '번째 데이터를 확인하세요.');
      gr_SellingFreightInfo.setFocusedCell(i, 'sellAmt');
      return false;
    }
    ;

    //삭제 시 내부거래 체크
    if (ds_SellingFreightInfo.getRowStatusValue(i) == 2) {
      scwin.f_postDtChk(rowData['odrNo'], rowData['sellSeq'], rowData['kcomcd'], rowData['seaAirCls'], rowData['blNo'], rowData['mhno']);
      let isPostDt = ds_postDtDataSet.getCellData(0, 'col1');
      if (isPostDt != '') {
        $c.win.alert($p, '내부거래 확정 건 입니다. \n' + 'Selling List ' + cntNum + '번째 데이터를 확인하세요.');
        return false;
      }
      ;
    }
    ;
  }
  ;

  // Partner
  rowCnt = ds_PartnerFreightInfo.getRowCount();
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_PartnerFreightInfo.getRowJSON(i);
    if (rowData['sellAmt'] == '0') {
      $c.win.alert($p, 'Amount(W) 금액이 0입니다. \nPartner List ' + i + '번째 데이터를 확인하세요.');
      gr_PartnerFreightInfo.setFocusedCell(i, 'sellAmt');
      scwin.f_selectTabMenu(1);
      return false;
    }
    ;

    //삭제 시 내부거래 체크
    if (ds_PartnerFreightInfo.getRowStatusValue(i) == 2) {
      scwin.f_postDtChk(rowData['odrNo'], rowData['sellSeq'], rowData['kcomcd'], rowData['seaAirCls'], rowData['blNo'], rowData['mhno']);
      let isPostDt = ds_postDtDataSet.getCellData(0, 'col1');
      if (isPostDt != '') {
        $c.win.alert($p, '내부거래 확정 건 입니다. \n' + 'Partner List ' + i + '번째 데이터를 확인하세요.');
        return false;
      }
      ;
    }
    ;
  }
  ;
  const targetGrid = [gr_BuyingFreightInfo, gr_SellingFreightInfo, gr_PartnerFreightInfo];
  let resVal = true;
  for (let i = 0; i < targetGrid.length; i++) {
    let retVal = await $c.gus.cfValidate($p, [targetGrid[i]], null, true);
    if (!retVal) {
      resVal = false;
      break;
    }
  }
  ;
  return resVal;
};

/**
 * @method 
 * @name f_Delete 
 * @description 삭제
 */
scwin.f_Delete = async function () {
  //삭제하시겠습니까?
  const retConfirm = await $c.win.confirm($p, E_MSG_CM_CRM_004);
  if (!retConfirm) return;
  scwin.actionFlag = 'Delete';
  await scwin.f_InvoiceCheck_All();
  if (scwin.spRtn == '0') {
    const gridDlts = [ds_HouseFreightInfo, ds_BuyingFreightInfo,
    // Buying Info
    ds_SellingFreightInfo,
    // Selling Info
    ds_PartnerFreightInfo // Partner Info
    ];
    gridDlts.forEach(dataList => {
      const rowCnt = dataList.getRowCount();
      for (let i = 0; i < rowCnt; i++) {
        dataList.deleteRow(i);
      }
      ;
    });
    await scwin.submitExcute(sbm_Save);
  } else {
    await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_002);
  }
  ;
  ed_blno.focus();
};

/**
 * @method 
 * @name f_Delete_callback 
 * @description 취소
 */
scwin.f_Cancel = function () {
  if (scwin.actionFlag == 'Create') {
    scwin.f_Set('INIT');
    scwin.processFlag = 'None';
  } else {
    scwin.f_Set('RETRIEVE');
  }
  ;
  ds_HouseFreightInfo.undoAll();
  const targetGrids = [gr_BuyingFreightInfo, gr_SellingFreightInfo, gr_PartnerFreightInfo];
  targetGrids.forEach(targetGrid => {
    const gridDlt = targetGrid._dataList;
    const rowCnt = gridDlt.getRowCount();
    for (let i = rowCnt; i >= 0; i--) {
      if (gridDlt.getRowStatus(i) == 'C') {
        gridDlt.removeRow(i);
      } else {
        gridDlt.undoRow(i);
      }
    }
    ;
    gridDlt.setRowPosition(0);
    targetGrid.setFocusedCell(0, 1);
  });
};

/**
 * @method 
 * @name f_Delete_callback 
 * @description 행추가
 * @param {string} gubun
 */
scwin.f_AddRow = function (gubun) {
  let houseRowData = dma_HouseFreightInfo.getJSON();
  let bilgClntNoVal, bilgClntNmVal, pchsClntNoVal, pchsClntNmVal, crcCdVal, exRateVal;
  let rowCnt, beforeRowData;
  switch (gubun) {
    case 'Selling':
      rowCnt = ds_SellingFreightInfo.getRowCount();
      beforeRowData = ds_SellingFreightInfo.getRowJSON(rowCnt - 1);

      // Default Setting
      //처음은 b/l 실화주  뿌려 주고 다음 부터는 바로 앞에 row 화주 뿌려줌
      if (rowCnt == 0) {
        bilgClntNoVal = houseRowData['ascd']; // 실화주  
        bilgClntNmVal = houseRowData['asnm']; // 실화주  
        crcCdVal = 'KRW';
        exRateVal = ed_rate.getValue();
      } else {
        bilgClntNoVal = beforeRowData['bilgClntNo'];
        bilgClntNmVal = beforeRowData['bilgClntNm'];
        crcCdVal = beforeRowData['crcCd'];
        exRateVal = beforeRowData['exRate'] || 0;
      }
      ;

      //Data Binding 
      data = [{
        'odrNo': houseRowData['odrNo'],
        // Order No
        'kcomcd': hd_kcomcd.getValue(),
        // 법인코드
        'seaAirCls': hd_seaAirCls.getValue(),
        // 해운/항공 구분 
        'blNo': ed_blno.getValue(),
        // Master Bill No
        'mhno': acb_hmhno.getValue(),
        // Consol No
        'locPtnCls': '1',
        // 국내해외매출 구분
        'mblHblCls': hd_mblHblCls.getValue(),
        // Master / House 구분
        'drcrCls': 'D',
        // 매출/매입 구분 
        'rsltsStdDt': houseRowData['cjdt'],
        // 실적 일자
        'bilgClntNo': bilgClntNoVal,
        'bilgClntNm': bilgClntNmVal,
        'crcCd': crcCdVal,
        'exRate': exRateVal
      }];
      ds_SellingFreightInfo.insertJSON(rowCnt, data);
      gr_SellingFreightInfo.setFocusedCell(rowCnt, 'bilgClntNo');

      // todo - tobe, asis 동작 달라 추가
      if (bilgClntNmVal == '') scwin.gr_SellingFreightInfo_onafteredit(rowCnt, 'bilgClntNo');
      break;
    case 'Partner':
      rowCnt = ds_PartnerFreightInfo.getRowCount();
      beforeRowData = ds_PartnerFreightInfo.getRowJSON(rowCnt - 1);

      // Default Setting
      // 처음은 b/l 파트너  뿌려 주고 다음 부터는 바로 앞에 row 화주 뿌려줌
      if (rowCnt == 0) {
        bilgClntNoVal = houseRowData['pncd']; // 파트너  
        bilgClntNmVal = houseRowData['pnnm']; // 파트너 
        crcCdVal = acb_cucd.getValue();
        exRateVal = ed_rate.getValue();
      } else {
        bilgClntNoVal = beforeRowData['bilgClntNo'];
        bilgClntNmVal = beforeRowData['bilgClntNm'];
        crcCdVal = beforeRowData['crcCd'];
        exRateVal = beforeRowData['exRate'] || 0;
      }
      ;

      //Data Binding 
      data = [{
        'odrNo': houseRowData['odrNo'],
        // Order No
        'kcomcd': hd_kcomcd.getValue(),
        // 법인코드
        'seaAirCls': hd_seaAirCls.getValue(),
        // 해운/항공 구분 
        'blNo': ed_blno.getValue(),
        // Master Bill No
        'mhno': acb_hmhno.getValue(),
        // Consol No
        'locPtnCls': '2',
        // 국내해외매출 구분
        'mblHblCls': hd_mblHblCls.getValue(),
        // Master / House 구분
        'rsltsStdDt': houseRowData['cjdt'],
        // 실적 일자	
        'bilgClntNo': bilgClntNoVal,
        'bilgClntNm': bilgClntNmVal,
        'crcCd': crcCdVal,
        'exRate': exRateVal,
        'drcrCls': 'C' // 매출/매입 구분
      }];
      ds_PartnerFreightInfo.insertJSON(rowCnt, data);
      gr_PartnerFreightInfo.setFocusedCell(rowCnt, 'bilgClntNo');
      break;
    case 'Buying':
      rowCnt = ds_BuyingFreightInfo.getRowCount();
      beforeRowData = ds_BuyingFreightInfo.getRowJSON(rowCnt - 1);

      // Default Setting
      //처음은 b/l 실화주  뿌려 주고 다음 부터는 바로 앞에 row 화주 뿌려줌 
      if (rowCnt == 0) {
        pchsClntNoVal = houseRowData['agcd']; // coload 업체   
        pchsClntNmVal = houseRowData['agnm']; // coload 업체   
        crcCdVal = 'KRW'; // acb_cucd.getValue();
        exRateVal = ed_rate.getValue();
      } else {
        pchsClntNoVal = beforeRowData['pchsClntNo'];
        pchsClntNmVal = beforeRowData['pchsClntNm'];
        crcCdVal = beforeRowData['crcCd'];
        exRateVal = beforeRowData['exRate'] || 0;
      }
      ;

      //Data Binding 
      data = [{
        'odrNo': houseRowData['odrNo'],
        // Order No
        'kcomcd': hd_kcomcd.getValue(),
        // 법인코드
        'seaAirCls': hd_seaAirCls.getValue(),
        // 해운/항공 구분 
        'blNo': ed_blno.getValue(),
        // Master Bill No
        'mhno': acb_hmhno.getValue(),
        // Consol No
        'locPtnCls': '1',
        // 국내해외매출 구분
        'mblHblCls': hd_mblHblCls.getValue(),
        // Master / House 구분
        'rsltsStdDt': houseRowData['cjdt'],
        // 실적 일자				
        'drcrCls': 'C',
        // 매출/매입 구분
        'pchsTyp': '1',
        'pchsClntNo': pchsClntNoVal,
        'pchsClntNm': pchsClntNmVal,
        'crcCd': crcCdVal,
        'exRate': exRateVal
      }];
      ds_BuyingFreightInfo.insertJSON(rowCnt, data);
      gr_BuyingFreightInfo.setFocusedCell(rowCnt, 'pchsTyp');
      gr_BuyingFreightInfo.setCellReadOnly(rowCnt, 'sellDeptCd', true);
      break;
    default:
      break;
  }
  ;
};

/**
 * @method 
 * @name f_Delete_callback 
 * @description 다중 행추가
 * @param {string} gubun
 */
scwin.f_AddRowMulti = function () {
  let sellingMakeRow = ed_rowMake_selling.getValue() || 1;
  let partnerMakeRow = ed_rowMake_partner.getValue() || 1;
  let buyingMakeRow = ed_rowMake_buying.getValue() || 1;
  let addRowCnt, gubun;
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      gubun = 'Selling';
      addRowCnt = $c.num.parseInt($p, sellingMakeRow, 0);
      break;
    case 1:
      gubun = 'Partner';
      addRowCnt = $c.num.parseInt($p, partnerMakeRow, 0);
      break;
    case 2:
      gubun = 'Buying';
      addRowCnt = $c.num.parseInt($p, buyingMakeRow, 0);
      break;
    default:
      break;
  }
  ;
  for (let i = 0; i < addRowCnt; i++) {
    scwin.f_AddRow(gubun);
  }
  ;
};

/**
 * @method 
 * @name f_Delete_callback 
 * @description 다중 행삭제
 */
scwin.f_DeleteAllRow = async function () {
  let ds = '';
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      ds = ds_SellingFreightInfo;
      break;
    case 1:
      ds = ds_PartnerFreightInfo;
      break;
    case 2:
      ds = ds_BuyingFreightInfo;
      break;
    default:
      break;
  }
  ;
  for (let i = ds.getRowCount() - 1; i >= 0; i--) {
    ds.setRowPosition(i);
    await scwin.f_DeleteRow();
  }
  ;
};

/**
 * @method 
 * @name f_DeleteRow 
 * @description 그리드  행삭제
 */
scwin.f_DeleteRow = async function () {
  let rowCnt, focusedIdx, rowData;
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      rowCnt = ds_SellingFreightInfo.getRowCount();
      focusedIdx = ds_SellingFreightInfo.getRowPosition();
      for (let i = 0; i < rowCnt; i++) {
        rowData = ds_SellingFreightInfo.getRowJSON(i);
        if (rowData['choice'] == 'T' || i == focusedIdx) {
          if (rowData['certiNo'] == '') {
            $c.data.deleteRow($p, ds_SellingFreightInfo);
          } else {
            // @은(는) @할 수 없습니다.
            await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ['Invoice No', 'delete']);
            return;
          }
          ;
        }
        ;
      }
      ;
      break;
    case 1:
      rowCnt = ds_PartnerFreightInfo.getRowCount();
      focusedIdx = ds_PartnerFreightInfo.getRowPosition();
      for (let i = 0; i < rowCnt; i++) {
        rowData = ds_PartnerFreightInfo.getRowJSON(i);
        if (rowData['choice'] == 'T' || i == focusedIdx) {
          if (rowData['certiNo'] == '') {
            $c.data.deleteRow($p, ds_PartnerFreightInfo);
          } else {
            // @은(는) @할 수 없습니다.
            await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ['Invoice No', 'delete']);
            return;
          }
          ;
        }
        ;
      }
      ;
      break;
    case 2:
      rowCnt = ds_BuyingFreightInfo.getRowCount();
      focusedIdx = ds_BuyingFreightInfo.getRowPosition();
      for (let i = 0; i < rowCnt; i++) {
        rowData = ds_BuyingFreightInfo.getRowJSON(i);
        if (rowData['choice'] == 'T' || i == focusedIdx) {
          if (rowData['pchsCertiNo'] == '') {
            $c.data.deleteRow($p, ds_BuyingFreightInfo);
          } else {
            // @은(는) @할 수 없습니다.
            await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ['Invoice No', 'delete']);
            return;
          }
          ;
        }
        ;
      }
      ;
      break;
    default:
      break;
  }
  ;
};

/**
 * @method 
 * @name f_DeleteRow 
 * @description 행취소
 * @param {string} gubun
 */
scwin.f_UndoRow = function (gubun) {
  let targetGrid, focusCell;
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      targetGrid = gr_SellingFreightInfo;
      focusCell = 'bilgClntNo';
      break;
    case 1:
      targetGrid = gr_PartnerFreightInfo;
      focusCell = 'bilgClntNo';
      break;
    case 2:
      targetGrid = gr_BuyingFreightInfo;
      focusCell = 'pchsTyp';
      break;
    default:
      break;
  }
  ;
  const gridDlt = targetGrid._dataList;
  const rowCnt = gridDlt.getRowCount();
  for (let i = rowCnt; i >= 0; i--) {
    if (gridDlt.getRowStatus(i) == 'C') {
      gridDlt.removeRow(i);
    } else {
      gridDlt.undoRow(i);
    }
  }
  ;
  gridDlt.setRowPosition(0);
  targetGrid.setFocusedCell(0, focusCell);
};

