scwin.f_ResultdateChange = async function () {
  const popupName = 'Result Date Change';
  let url = '/ui/il/common/xml/ilCommonResultDateChange.xml';
  let options = {
    width: '460px',
    height: '280px',
    popupName: popupName,
    title: popupName
  };
  let rtnList = await $c.win.openPopup($p, url, options);
  if (typeof rtnList != 'undefined') {
    if (rtnList[0] == 'N/A') scwin.f_GridResultdateChange(rtnList);
  }
  ;
};

/**
 * @method 
 * @name f_GridResultdateChange
 * @description
 */
scwin.f_GridResultdateChange = async function (rtnList) {
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      // Selling
      if (ds_SellingFreightInfo.getRowCount() == '0') {
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, ['Selling Information']); //  @이(가) 존재하지 않습니다.		
        return;
      }
      ;
      break;
    case 1:
      // partner
      if (ds_PartnerFreightInfo.getRowCount() == '0') {
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, ['Partner Information']); //  @이(가) 존재하지 않습니다.	
        return;
      }
      ;
      break;
    case 2:
      // Buying 
      if (ds_BuyingFreightInfo.getRowCount() == '0') {
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, ['Buying Information']); //  @이(가) 존재하지 않습니다.	
        return;
      }
      ;
      break;
    default:
      break;
  }
  ;
  const retConfirm = await $c.win.confirm($p, E_MSG_CM_CRM_001);
  if (!retConfirm) return;
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      for (let i = 0; i < ds_SellingFreightInfo.getRowCount(); i++) {
        if (ds_SellingFreightInfo.getCellData(i, 'certiNo') == '') {
          ds_SellingFreightInfo.setCellData(i, 'rsltsStdDt', rtnList[1]);
        }
        ;
      }
      ;
      break;
    case 1:
      for (let i = 0; i < ds_PartnerFreightInfo.getRowCount(); i++) {
        if (ds_PartnerFreightInfo.getCellData(i, 'certiNo') == '') {
          ds_PartnerFreightInfo.setCellData(i, 'rsltsStdDt', rtnList[1]);
        }
        ;
      }
      ;
      break;
    case 2:
      for (let i = 0; i < ds_BuyingFreightInfo.getRowCount(); i++) {
        if (ds_BuyingFreightInfo.getCellData(i, 'pchsCertiNo') == '') {
          ds_BuyingFreightInfo.setCellData(i, 'rsltsStdDt', rtnList[1]);
        }
        ;
      }
      ;
      break;
    default:
      break;
  }
  ;
};

/**
 * @method 
 * @name f_CustomerChange
 * @description Customer Change
 */
scwin.f_CustomerChange = async function () {
  let options = {
    width: '460px',
    height: '240px',
    popupName: 'Customer Change',
    title: 'Customer Change'
  };
  let url = '/ui/il/common/xml/ilCommonCustomerChange.xml';
  let rtnList = await $c.win.openPopup($p, url, options);
  if ($c.util.isEmpty($p, rtnList)) return;
  if (rtnList[0] != 'N/A') return;
  scwin.f_GridCustomerChange(rtnList);
};

/**
 * @method 
 * @name f_GridCustomerChange
 * @description Customer Change
 * @param {array} rtnList 
 */
scwin.f_GridCustomerChange = async function (rtnList) {
  let grid, errorParam, certiNo, clntNo, clntNm;
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      // Selling
      grid = ds_SellingFreightInfo;
      errorParam = ['Selling Information'];
      certiNo = 'certiNo';
      clntNo = 'bilgClntNo';
      clntNm = 'bilgClntNm';
      break;
    case 1:
      // partner
      grid = ds_PartnerFreightInfo;
      errorParam = ['Partner Information'];
      certiNo = 'certiNo';
      clntNo = 'bilgClntNo';
      clntNm = 'bilgClntNm';
      break;
    case 2:
      // Buying
      grid = ds_BuyingFreightInfo;
      errorParam = ['Buying Information'];
      certiNo = 'pchsCertiNo';
      clntNo = 'pchsClntNo';
      clntNm = 'pchsClntNm';
      break;
    default:
      break;
  }
  ;
  if (grid.getRowCount() == '0') {
    //  @이(가) 존재하지 않습니다.		
    $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, errorParam);
    return;
  }
  ;

  // 저장하시겠습니까?
  const retConfirm = await $c.win.confirm($p, E_MSG_CM_CRM_001);
  if (!retConfirm) return;
  let rowCnt = grid.getRowCount();
  for (let i = 0; i < rowCnt; i++) {
    const rowData = grid.getRowJSON(i);
    if (rowData[certiNo] == '' && rowData['pchsClntNo'] == rtnList[1]) {
      grid.setCellData(i, clntNo, rtnList[3]);
      grid.setCellData(i, clntNm, rtnList[4]);
    }
    ;
  }
  ;
};

/**
 * @method 
 * @name f_dataset_exist_choice
 * @description DateSet중 Choice 컬럼이 T인 값이 잇는지를 체크하는 함수 
 * 없으면 데이터셋이 없다는 메세지를 출력한다.
 * @param {object[]} dataset
 * @param {string} message
 */
scwin.f_dataset_exist_choice = function (dataset, message) {
  let T_count = 0;
  let rowCnt = dataset.getRowCount();
  for (let i = 0; i < rowCnt; i++) {
    if (dataset.getCellData(i, 'choice') == 'T') {
      T_count++;
    }
    ;
  }
  ;
  if (T_count == 0) {
    $c.win.alert($p, message);
    return false;
  }
  ;
  return true;
};

//-------------------------------------------------------------------------
// Ex-rate Change2
// 작성 일자 : 20110906 
// 기존 Ex-rate Change 함수 대비 변경사항이 너무 많아서, 
// 신규 함수 Ex-rate Change2 로 신규 작성
//
// 기존 프로세스 ( function Ex-rate Change )
// 기존의 함수 Ex-rate Change는 그리드에 커서가 위치해 있는 로우만 처리하고 아래프로세스를 따른다. 
// 1. 현재 보고있는 Grid의 Date셋에 데이터가 있는지 검증 
// 2. 저장하시겟습니까?  Y/N 메세지 출력후 Y일때 진행
// 3. CertiNo컬럼에 데이터가 있는지 검사 => 없으면, ed_rate.getValue() (그리드 바로 윗줄의 Ex-rate) 를 입력
// 4. 그리드의 scwin.CRC 코드가 무엇인지 검사
//    4-1. KOR이면 아무것도 하지 않는다.
//         4-2-1. 그리드의 CRC컬럼에 acb_cucd(그리드 바로윗줄의 Currency 콤보박스) 의 데이터를 입력한다. 
//    4-2. 그외는
//         4-2-2. SellAmt에 ds_selling Row의 SellAmtFcrc*exRate . nunit 해서 데이터를 기입한다. 
//                여기서 nunit은 통화의 종류에 따라 저장되는 값이 틀려 요율계산을 다르게 해줘야 되는 상황이다. (% 일본 이탈리아 인도 스페인의 경우 100을 사용 )
// 5.VAT확인
//   vatYn이 0 이면      vatAmt에 0대입
//   vatYn이 0 이 아니면 vat값 계산 ROUND('sellAmt') * 0.1) * 100) / 100                 
//                                  소수점 첫재자리로 반올림 처리 
//
// 신규 프로세스
// 그리드 변경사항
// 2. CRC(통화코드)가 acb_cucd 콤보박스 데이터와 연결되어 있엇는데, 이 콤보박스를 무시하고,
// 1. Selling Patner Buying 탭 모두 Choice 라는 체크박스를 두고, 체크되어 있는 전체 로우를 처리한다.
//    그리드 자체에 콤보박스를 추가한다.
//
// 프로세스 순서
// 1. 현재 사용중인 탭에 데이터셋없으면 에러메세지를 출력하고 종료
// 2. 데이터셋에 choice컬럼이 T로 체크된 로우가 없으면, 에러메세지를 출력하고 종료
// 3. 저장하시겟습니까?  Y/N 메세지 출력후 Y일때 진행
// 4. 전체 데이터셋 갯수만큼 루프시작
//    choice 컬럼이 T이고, Invoice_No가 '' (공백)일때 아래 5번부터 7번까지 항목을 진행한다.
// 5. ex-rate 기입
//    조회된 데이터셋의 CRC(통화종류가) 전부 USD이면 Ex-rate의 값을 기입하고,
//    그외의 경우는 USD는 US-Ex-rate(그리드 윗줄 에디트박스), 그외는 Ex-rate(그리드윗줄 에디트박스)의 값을 exrate(그리드)에 기입한다.
// 6. 그리드의 scwin.CRC 코드가 무엇인지 검사
//    5-1. KOR이면 아무것도 하지 않는다.
//    5-2. 그외는 SellAmt에 ds_selling Row의 SellAmtFcrc*exRate . nunit 해서 데이터를 기입한다.
// 7. VAT확인
//    vatYn이 0 이면      vatAmt에 0대입
//    vatYn이 0 이 아니면 vat값 계산 ROUND('sellAmt') * 0.1) * 100) / 100
//                                   소수점 첫재자리 반올림 처리
//
//-------------------------------------------------------------------------

/**
 * @method 
 * @name f_exRateChange2
 * @description 
 */
scwin.f_exRateChange2 = async function () {
  let dataset;
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      // Selling 탭 일경우
      dataset = ds_SellingFreightInfo;

      // 1. 현재 사용중인 탭에 데이터셋없으면 에러메세지를 출력하고 종료 
      if (dataset.getRowCount() == '0') {
        // @이(가) 존재하지 않습니다.		
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, ['Selling Information']);
        return;
      }
      ;

      // 2. 데이터셋에 choice컬럼이 T로 체크된 로우가 없으면, 에러메세지를 출력하고 종료  
      if (!scwin.f_dataset_exist_choice(dataset, 'There is no Selling Information Choice')) {
        return;
      }
      ;
      break;
    case 1:
      // partner 탭 일경우
      dataset = ds_PartnerFreightInfo;

      // 1. 현재 사용중인 탭에 데이터셋없으면 에러메세지를 출력하고 종료 
      if (dataset.getRowCount() == '0') {
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, ['Partner Information']); //  @이(가) 존재하지 않습니다.	
        return;
      }
      ;

      // 2. 데이터셋에 choice컬럼이 T로 체크된 로우가 없으면, 에러메세지를 출력하고 종료  
      if (!scwin.f_dataset_exist_choice(dataset, 'There is no Selling Information Choice')) {
        return;
      }
      ;
      break;
    case 2:
      // Buying 탭 일경우
      dataset = ds_BuyingFreightInfo;

      // 1. 현재 사용중인 탭에 데이터셋없으면 에러메세지를 출력하고 종료 
      if (dataset.getRowCount() == '0') {
        $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, ['Buying Information']); //  @이(가) 존재하지 않습니다.	
        return;
      }
      ;

      // 2. 데이터셋에 choice컬럼이 T로 체크된 로우가 없으면, 에러메세지를 출력하고 종료  
      if (!scwin.f_dataset_exist_choice(dataset, 'There is no Selling Information Choice')) {
        return;
      }
      ;
      break;
    default:
      break;
  }
  ;

  // 3. 저장하시겟습니까?  Y/N 메세지 출력후 Y일때 진행
  const retConfirm = await $c.win.confirm($p, E_MSG_CM_CRM_001);
  if (!retConfirm) return;
  let USD_COUNT, DS_COUNT;
  let nUnit = 1;
  nUnit = scwin.f_Currency_Unit(acb_cucd.getValue());
  switch (tr_tab.getSelectedTabIndex()) {
    case 0:
      // 4.전체 조회된 통화 데이터 조회 USD일경우 USD_COUNT 변수를 증가시키고, 
      // 나중에 USD_COUNT와 DS_COUNT를 비교하여 전부가 USD인지를 도출한다. 
      USD_COUNT = 0;
      DS_COUNT = dataset.getRowCount();
      for (let j = 0; j < DS_COUNT; j++) {
        if (dataset.getCellData(j, 'crcCd') == 'USD') {
          USD_COUNT++;
        }
        ;
      }
      ;

      // 4. 전체 데이터셋 갯수만큼 루프시작
      //    choice 컬럼이 T이고, Invoice_No가 '' (공백)일때 아래 5번부터 8번까지 항목을 진행한다. 
      for (let i = 0; i < dataset.getRowCount(); i++) {
        let rowData = dataset.getRowJSON(i);

        // 선택된 행만 처리 
        if (rowData['choice'] == 'T' && rowData['certiNo'] == '') {
          // 5. ex-rate 기입 조회된 데이터셋의 CRC(통화종류가) 전부 USD이면 Ex-rate의 값을 기입하고, 
          //    그외의 경우는 USD는 US-Ex-rate(그리드 윗줄 에디트박스), 
          //    그외는 Ex-rate(그리드윗줄 에디트박스)의 값을 exrate(그리드)에 기입한다.
          // 그리드에 표시된 데이터의 통화코드분포 유형 체크 USD의 숫자와 그리드 로우수를 비교하여 산출한다. 

          // 그리드에 표시된 전체 데이터가 USD이면 
          if (USD_COUNT == DS_COUNT) {
            dataset.setCellData(i, 'exRate', ed_rate.getValue()); //ex-rate
          }
          // 통화가 섞여 있는경우 
          else {
            if (rowData['crcCd'] == 'USD') {
              dataset.setCellData(i, 'exRate', ed_exrate.getValue());
            } else {
              dataset.setCellData(i, 'exRate', ed_rate.getValue());
            }
          }

          // 6. 그리드의 CRC 코드가 무엇인지 검사
          //   6-1. KOR이면 아무것도 하지 않는다.
          //   6-2. 그외는 SellAmt에 ds_selling Row의 SellAmtFcrc*exRate . nunit 해서 데이터를 기입한다. 
          let sellAmt = Math.round(rowData['sellAmtFcrc'] * rowData['exRate']) / nUnit;
          if (rowData['crcCd'] != 'KRW') {
            dataset.setCellData(i, 'sellAmt', sellAmt);
          }
          ;

          // 7. VAT확인 
          //    vatYn이 0 이면      vatAmt에 0대입
          //    vatYn이 0 이 아니면 vat값 계산 ROUND('sellAmt') * 0.1) * 100) / 100                 
          //                                   소수점 첫재자리로 반올림 처리 
          let vatAmt = Math.round(rowData['sellAmt'] * 0.1 * 100) / 100;
          if (rowData['vatYn'] == '0') vatAmt = 0;
          dataset.setCellData(i, 'vatAmt', vatAmt);
        }
        ;
      }
      ;
      break;
    case 1:
      // 4.전체 조회된 통화 데이터 조회 USD일경우 USD_COUNT 변수를 증가시키고, 나중에 USD_COUNT와 DS_COUNT를 비교하여 전부가 USD인지를 도출한다. 
      USD_COUNT = 0;
      DS_COUNT = dataset.getRowCount();
      for (let j = 0; j < DS_COUNT; j++) {
        if (dataset.getCellData(j, 'crcCd') == 'USD') {
          USD_COUNT++;
        }
        ;
      }
      ;

      // 4. 전체 데이터셋 갯수만큼 루프시작
      //    choice 컬럼이 T이고, Invoice_No가 '' (공백)일때 아래 5번부터 8번까지 항목을 진행한다. 
      for (let i = 0; i < dataset.getRowCount(); i++) {
        let rowData = dataset.getRowJSON(i);

        // 선택된 행만 처리 
        if (rowData['choice'] == 'T' && rowData['certiNo'] == '') {
          // 5. ex-rate 기입 조회된 데이터셋의 CRC(통화종류가) 전부 USD이면 Ex-rate의 값을 기입하고, 
          //    그외의 경우는 USD는 US-Ex-rate(그리드 윗줄 에디트박스), 
          //    그외는 Ex-rate(그리드윗줄 에디트박스)의 값을 exrate(그리드)에 기입한다.
          // 그리드에 표시된 데이터의 통화코드분포 유형 체크 USD의 숫자와 그리드 로우수를 비교하여 산출한다. 
          // 그리드에 표시된 전체 데이터가 USD이면 
          if (USD_COUNT == DS_COUNT) {
            dataset.setCellData(i, 'exRate', ed_rate.getValue()); //ex-rate
          }
          // 통화가 섞여 있는경우 
          else {
            if (rowData['crcCd'] == 'USD') {
              dataset.setCellData(i, 'exRate', ed_exrate.getValue());
            } else {
              dataset.setCellData(i, 'exRate', ed_rate.getValue());
            }
          }

          // 6. 그리드의 CRC 코드가 무엇인지 검사
          //   6-1. KOR이면 아무것도 하지 않는다.
          //   6-2. 그외는 SellAmt에 ds_selling Row의 SellAmtFcrc*exRate . nunit 해서 데이터를 기입한다. 
          let sellAmt = Math.round(rowData['sellAmtFcrc'] * rowData['exRate'] / nUnit);
          if (rowData['crcCd'] != 'KRW') {
            dataset.setCellData(i, 'sellAmt', sellAmt);
          }
          ;

          // 7. VAT확인 
          //    vatYn이 0 이면      vatAmt에 0대입
          //    vatYn이 0 이 아니면 vat값 계산 ROUND('sellAmt') * 0.1) * 100) / 100                 
          //                                   소수점 첫재자리로 반올림 처리 
          let vatAmt = Math.round(rowData['sellAmt'] * 0.1 * 100) / 100;
          if (rowData['vatYn'] == '0') vatAmt = 0;
          dataset.setCellData(i, 'vatAmt', vatAmt);
        }
        ;
      }
      ;
      break;
    case 2:
      // 4.전체 조회된 통화 데이터 조회 USD일경우 USD_COUNT 변수를 증가시키고, 나중에 USD_COUNT와 DS_COUNT를 비교하여 전부가 USD인지를 도출한다. 
      USD_COUNT = 0;
      DS_COUNT = dataset.getRowCount();
      for (let j = 0; j < DS_COUNT; j++) {
        if (dataset.getCellData(j, 'crcCd') == 'USD') {
          USD_COUNT++;
        }
        ;
      }
      ;

      // 4. 전체 데이터셋 갯수만큼 루프시작
      //    choice 컬럼이 T이고, Invoice_No가 '' (공백)일때 아래 5번부터 8번까지 항목을 진행한다. 
      for (let i = 0; i < DS_COUNT; i++) {
        let rowData = dataset.getRowJSON(i);

        // 선택된 행만 처리 
        if (rowData['choice'] == 'T' && rowData['pchsCertiNo'] == '') {
          // 5. ex-rate 기입 조회된 데이터셋의 CRC(통화종류가) 전부 USD이면 Ex-rate의 값을 기입하고, 
          //    그외의 경우는 USD는 US-Ex-rate(그리드 윗줄 에디트박스), 그외는 Ex-rate(그리드윗줄 에디트박스)의 값을 exrate(그리드)에 기입한다.
          // 그리드에 표시된 데이터의 통화코드분포 유형 체크 USD의 숫자와 그리드 로우수를 비교하여 산출한다. 
          // 그리드에 표시된 전체 데이터가 USD이면 
          if (USD_COUNT == DS_COUNT) {
            dataset.setCellData(i, 'exRate', ed_rate.getValue()); //ex-rate
          }
          // 통화가 섞여 있는경우 
          else {
            if (rowData['crcCd'] == 'USD') {
              dataset.setCellData(i, 'exRate', ed_exrate.getValue());
            } else {
              dataset.setCellData(i, 'exRate', ed_rate.getValue());
            }
          }

          // 6. 그리드의 CRC 코드가 무엇인지 검사
          //   6-1. KOR이면 아무것도 하지 않는다.
          //   6-2. 그외는 SellAmt에 ds_selling Row의 SellAmtFcrc*exRate . nunit 해서 데이터를 기입한다. 							
          let pchsAmt = Math.round(rowData['pchsAmtFcrc'] * rowData['exRate'] / nUnit);
          if (rowData['crcCd'] != 'KRW') {
            dataset.setCellData(i, 'pchsAmt', pchsAmt);
          }
          ;

          // 7. VAT확인 
          //    vatYn이 0 이면      vatAmt에 0대입
          //    vatYn이 0 이 아니면 vat값 계산 ROUND('sellAmt') * 0.1) * 100) / 100                 
          //                                   소수점 첫재자리로 반올림 처리 
          let vatAmt = Math.round(rowData['sellAmt'] * 0.1 * 100) / 100;
          if (rowData['vatYn'] == '0') {
            vatAmt = 0;
          }
          dataset.setCellData(i, 'vatAmt', vatAmt);
        }
        ;
      }
      ;
      break;
    default:
      break;
  }
  ;
};

