/**
 * @method 
 * @name f_JobCloseYn
 * @description Result Date의 회계마감 여부를 체크하는 함수 : 회계마감된 월로는  실적일자 입력 불가능
 */
scwin.f_JobCloseYn = async function () {
  let rowCnt, rsltsStdDt, rsltsDt, isCloseDepr;
  let preWrkNo = 'FI01'; // 월 마감코드
  let minRsltsDt = scwin.strCurDate.slice(0, 6); // 실적일자 회계마감 여부 CHECK	 

  let listNames = ['Selling', 'Partner', 'Buying'];
  let dlts = [ds_SellingFreightInfo, ds_PartnerFreightInfo, ds_BuyingFreightInfo];
  for (let i = 0; i < dlts.length; i++) {
    const targetDlt = dlts[i];
    rowCnt = targetDlt.getRowCount();
    for (let j = 0; j < rowCnt; j++) {
      if (targetDlt.getRowStatusValue(j) == '2') {
        //운임 신규 생성일때
        rsltsStdDt = targetDlt.getCellData(j, 'rsltsStdDt').slice(0, 6);
        rsltsDt = rsltsStdDt < minRsltsDt ? rsltsStdDt : minRsltsDt;
        isCloseDepr = await udc_closeDepr.cfJobCloseYN('CUR', rsltsDt, '00', preWrkNo, '0', '', '', '000');
        if (isCloseDepr == '2' || isCloseDepr == 'DNF') {
          await $c.gus.cfAlertMsg($p, '회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \n' + listNames[i] + ' List Result Date를 확인하세요.');
          return false;
        }
        ;
      }
      ;
    }
    ;
  }
  ;
  return true;
};

