//-----------------------------------------------------------------------------

/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {
  let submitObj = $p.getComponentById(e.id);
  switch (submitObj) {
    case sbm_RetrieveProfit:
      let profitData = ds_profit.getRowJSON(0);
      ed_selling_total.setValue(profitData['sellAmt']);
      ed_purchase_total.setValue(profitData['pchsAmt']);
      ed_profit_total.setValue(profitData['profit']);
      ed_profitRate_total.setValue(profitData['profitRate']);
      break;
    case sbm_Retrieve:
      // Success
      const houseData = ds_HouseFreightInfo.getRowJSON(0);
      dma_HouseFreightInfo.setJSON(houseData);
      totalRows1.setValue(ds_SellingFreightInfo.getRowCount());
      totalRows2.setValue(ds_PartnerFreightInfo.getRowCount());
      totalRows3.setValue(ds_BuyingFreightInfo.getRowCount());
      switch (tr_tab.getSelectedTabIndex()) {
        case 0:
          gr_SellingFreightInfo.setFocusedCell(0, 0);
          break;
        case 1:
          gr_PartnerFreightInfo.setFocusedCell(0, 0);
          break;
        case 2:
          gr_BuyingFreightInfo.setFocusedCell(0, 0);
          break;
        default:
          break;
      }
      ;

      // OnSuccess
      if (ds_HouseFreightInfo.getRowCount() == 0) {
        scwin.f_ProcessResult('None');
      } else {
        scwin.f_ProcessResult('FreightInfo');
      }
      ;
      if (scwin.v_linkcheck == 9) {
        scwin.f_Set('UPDATE');
        let row_cnt = scwin.p_row_cnt;
        let data = scwin.p_data;
        let rtnValues = data.split('$');
        for (let t = 0; t < row_cnt; t++) {
          rtnValues[t] = rtnValues[t].split('_');
        }
        ;
        let k = ds_BuyingFreightInfo.getRowCount();
        if (rtnValues == null) return false;
        for (let i = k; i < rtnValues.length + k; i++) {
          scwin.f_AddRow('Buying');
          dma_frt_condition.setCellData(1, 'fromCd', rtnValues[i - k][2]);
          await scwin.submitExcute(sbm_retrieve_frtMapping);
          let frtMapping = ds_frtMapping.getRowJSON(0);
          let focusedIdx = ds_BuyingFreightInfo.getRowPosition();
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'fareEngCd', frtMapping['toCd']);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'fareEngNm', frtMapping['description']);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'selpchItemCd', frtMapping['dtlCd1']);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'fareGrpCd', frtMapping['dtlCd2']);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'vatYn', frtMapping['dtlCd3']);
          if (ds_BuyingFreightInfo.getCellData(focusedIdx, 'vatYn') != 0) {
            ds_BuyingFreightInfo.setCellData(focusedIdx, 'vat', Math.round(rtnValues[i - k][6] * 0.1 - 0.5));
          }
          ;
          gr_BuyingFreightInfo.setFocusedCell(i, 'pchsTyp');
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'pchsClntNo', rtnValues[i - k][0]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'pchsClntNm', rtnValues[i - k][1]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'fareEngCd', rtnValues[i - k][2]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'crcCd', rtnValues[i - k][3]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'pchsAmtFcrc', rtnValues[i - k][4]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'exRate', rtnValues[i - k][5]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'pchsAmt', rtnValues[i - k][6]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'chgWt', rtnValues[i - k][7]);
          ds_BuyingFreightInfo.setCellData(focusedIdx, 'pchsUpr', rtnValues[i - k][8]);
        }
        ;
        tr_tab.setSelectedTabIndex(2);
      }
      ;
      scwin.ds_HouseFreightInfo_OnLoadCompleted();
      break;
    case sbm_Save:
      // OnSuccess
      if (scwin.actionFlag == 'Save') {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_001); // 성공적으로 저장하였습니다 	
        scwin.f_MhnoLoading(); // 저장 후 MHNO 검색 				
      }
      ;
      if (scwin.actionFlag == 'Delete') {
        // todo - 동작이 달라 추가
        dma_HouseFreightInfo.setEmptyValue();
        ds_BuyingFreightInfo.removeAll();
        ds_SellingFreightInfo.removeAll();
        ds_PartnerFreightInfo.removeAll();
        await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_004); // 성공적으로 삭제하였습니다 		
      }
      ;
      scwin.processFlag = 'None';
      scwin.f_Retrieve();
      scwin.f_Set('SAVE');
      break;
    case sbm_RetrieveTmp:
      let rowCnt;
      let houseRowData = dma_HouseFreightInfo.getJSON();
      switch (scwin.TabIndex) {
        case 0:
          // Selling 
          //Data Binding 
          rowCnt = ds_SellingFreightInfo.getRowCount();
          for (let i = 0; i < rowCnt; i++) {
            ds_SellingFreightInfo.setCellData(i, 'odrNo', houseRowData['odrNo']); // Order No
            ds_SellingFreightInfo.setCellData(i, 'kcomcd', hd_kcomcd.getValue()); // 법인코드
            ds_SellingFreightInfo.setCellData(i, 'seaAirCls', hd_seaAirCls.getValue()); // 해운/항공 구분 
            ds_SellingFreightInfo.setCellData(i, 'blNo', ed_blno.getValue()); // Master Bill No
            ds_SellingFreightInfo.setCellData(i, 'mhno', acb_hmhno.getValue()); // Consol No
            ds_SellingFreightInfo.setCellData(i, 'locPtnCls', '1'); // 국내해외매출 구분
            ds_SellingFreightInfo.setCellData(i, 'mblHblCls', hd_mblHblCls.getValue()); // Master / House 구분
            ds_SellingFreightInfo.setCellData(i, 'drcrCls', 'D'); // 매출/매입 구분 
            ds_SellingFreightInfo.setCellData(i, 'rsltsStdDt', houseRowData['cjdt']); // 실적 일자
            ds_SellingFreightInfo.modifyRowStatus(i, 'C');
          }
          ;
          $c.gus.cfDisableObjects($p, [udc_bottomBtn_Selling, btn_DeleteAllRow_Selling]);
          break;
        case 1:
          // partner 
          rowCnt = ds_PartnerFreightInfo.getRowCount();
          for (let i = 0; i < rowCnt; i++) {
            ds_PartnerFreightInfo.setCellData(i, 'odrNo', houseRowData['odrNo']); // Order No
            ds_PartnerFreightInfo.setCellData(i, 'kcomcd', hd_kcomcd.getValue()); // 법인코드
            ds_PartnerFreightInfo.setCellData(i, 'seaAirCls', hd_seaAirCls.getValue()); // 해운/항공 구분 
            ds_PartnerFreightInfo.setCellData(i, 'blNo', ed_blno.getValue()); // Master Bill No
            ds_PartnerFreightInfo.setCellData(i, 'mhno', acb_hmhno.getValue()); // Consol No
            ds_PartnerFreightInfo.setCellData(i, 'locPtnCls', '2'); // 국내해외매출 구분
            ds_PartnerFreightInfo.setCellData(i, 'mblHblCls', hd_mblHblCls.getValue()); // Master / House 구분
            ds_PartnerFreightInfo.setCellData(i, 'rsltsStdDt', houseRowData['cjdt']); // 실적 일자        
            ds_PartnerFreightInfo.setCellData(i, 'drcrCls', 'C');
            ds_PartnerFreightInfo.modifyRowStatus(i, 'C');
          }
          ;
          $c.gus.cfDisableObjects($p, [udc_bottomBtn_Selling, btn_DeleteAllRow_Partner]);
          break;
        case 2:
          // Buying
          rowCnt = ds_BuyingFreightInfo.getRowCount();
          for (let i = 0; i < ds_BuyingFreightInfo.getRowCount(); i++) {
            ds_BuyingFreightInfo.setCellData(i, 'odrNo', houseRowData['odrNo']); // Order No
            ds_BuyingFreightInfo.setCellData(i, 'kcomcd', hd_kcomcd.getValue()); // 법인코드
            ds_BuyingFreightInfo.setCellData(i, 'seaAirCls', hd_seaAirCls.getValue()); // 해운/항공 구분 
            ds_BuyingFreightInfo.setCellData(i, 'blNo', ed_blno.getValue()); // Master Bill No
            ds_BuyingFreightInfo.setCellData(i, 'mhno', acb_hmhno.getValue()); // Consol No
            ds_BuyingFreightInfo.setCellData(i, 'locPtnCls', '1'); // 국내해외매출 구분
            ds_BuyingFreightInfo.setCellData(i, 'mblHblCls', hd_mblHblCls.getValue()); // Master / House 구분
            ds_BuyingFreightInfo.setCellData(i, 'rsltsStdDt', houseRowData['cjdt']); // 실적 일자                
            ds_BuyingFreightInfo.setCellData(i, 'drcrCls', 'C'); // 매출/매입 구분     
            ds_BuyingFreightInfo.setCellData(i, 'pchsTyp', '1');
            ds_BuyingFreightInfo.modifyRowStatus(i, 'C');
          }
          ;
          $c.gus.cfDisableObjects($p, [udc_bottomBtn_Selling, btn_DeleteAllRow_Buying]);
          break;
        default:
          break;
      }
      ;
      break;
    case sbm_hmhno:
      // for=ds_hmhno event=OnLoadCompleted(rowcnt)
      if (scwin.linkType == 'BL_LINK') {
        scwin.linkType = '';
        scwin.f_Retrieve();
      } else if (scwin.linkType == 'API_LINK') {
        scwin.linkType = '';
        scwin.f_Retrieve();
      }
      break;
    case sbm_InvoiceCheck:
      ds_InvoiceCheck.setRowPosition(0);
      break;
    default:
      break;
  }
};

/**
 * @method 
 * @name ds_HouseFreightInfo_OnLoadCompleted
 * @description for=ds_HouseFreightInfo event=OnLoadCompleted(rowcnt) 
 */
scwin.ds_HouseFreightInfo_OnLoadCompleted = function () {
  let rowCnt = ds_HouseFreightInfo.getRowCount();
  let rowData = ds_HouseFreightInfo.getRowJSON(ds_HouseFreightInfo.getRowPosition() ?? 0);
  if (rowCnt > 0 && rowData['rate'] != '0') {
    scwin.exRate1 = rowData['rate'];
    scwin.crc = rowData['cucd'];
    scwin.exRateCheck = '3';
  }
  ;
  if (rowCnt > 0 && rowData['exrate'] != '0') {
    scwin.exRate2 = rowData['exrate'];
  }
  ;
};

/**
 * @event 
 * @name sbm_Save_submit
 * @description Save 요청 전
 */
scwin.sbm_Save_submit = function (e) {
  let rowData = dma_HouseFreightInfo.getJSON();
  ds_HouseFreightInfo.setRowJSON(0, rowData, true);
};

/**
 * @method 
 * @name dlt_onload 
 * @description DataList의 데이터가 전체적으로 변경(set)되는 경우 발생
 */
scwin.dlt_onload = function () {
  if (this.getRowPosition() == null && this.getRowCount() > 0) {
    this.setRowPosition(0);
    scwin.gridSetFocus(this, 'currow', 0, gr_SellingFreightInfo, totalRows1);
    scwin.gridSetFocus(this, 'currow', 0, gr_PartnerFreightInfo, totalRows2);
    scwin.gridSetFocus(this, 'currow', 0, gr_BuyingFreightInfo, totalRows3);
  }
  ;
};

/**
 * @method 
 * @name dlt_oninsertrow 
 * @description 새로운 행이 추가된 후에 발생 (여러 행이 동시에 추가되면 한번만 발생)
 */
scwin.dlt_oninsertrow = function (info) {
  if (Object.keys(info.insertedDataObj).length < 1) return;
  const rowIdx = Object.keys(info.insertedDataObj)[0] ?? 0;
  this.setRowPosition(rowIdx);
  scwin.gridSetFocus(this, 'currow', rowIdx, gr_SellingFreightInfo, totalRows1);
  scwin.gridSetFocus(this, 'currow', rowIdx, gr_PartnerFreightInfo, totalRows2);
  scwin.gridSetFocus(this, 'currow', rowIdx, gr_BuyingFreightInfo, totalRows3);
};

/**
 * @method 
 * @name dlt_onremoverow 
 * @description 행이 제거된 후에 발생 (여러 행이 동시에 제거되면 한번만 발생)
 */
scwin.dlt_onremoverow = function (info) {
  if (Object.keys(info.removedDataObj).length < 1) return;
  const rowIdx = Number(Object.keys(info.removedDataObj)[0]) - 1;
  const clacIdx = rowIdx == -1 ? 0 : rowIdx;
  this.setRowPosition(clacIdx);
  scwin.gridSetFocus(this, 'currow', clacIdx, gr_SellingFreightInfo, totalRows1);
  scwin.gridSetFocus(this, 'currow', clacIdx, gr_PartnerFreightInfo, totalRows2);
  scwin.gridSetFocus(this, 'currow', clacIdx, gr_BuyingFreightInfo, totalRows3);
};

/**
 * @method 
 * @name gridSetFocus 
 * @description dataList 이벤트 후 그리드 실제 포커스 처리
 */
scwin.gridSetFocus = function (dataList, defaultCol, rowIndex, targetGrid, targetRows) {
  if (dataList != targetGrid._dataList) return;
  const focusCol = targetGrid.getFocusedColumnID() ?? defaultCol;
  targetGrid.setFocusedCell(rowIndex, focusCol);
  targetRows.setValue(dataList.getRowCount());
};

