/**
 * @event 
 * @name ica_exdt_onchange
 * @description Ex-Rate Date component의 value가 변경되었을 때 발생
 */
scwin.ica_exdt_onblur = async function () {
  // for=ed_exdt event=onKillFocus()>

  // Ex-Rate 가져 오기
  let param1 = acb_cucd.getValue();
  let param2 = ica_exdt.getValue();
  let param3 = acb_exgb.getValue();
  if (ed_rate.getValue() == '') ed_rate.setValue(0);
  if (ed_exrate.getValue() == '') ed_exrate.setValue(0);

  //이규복씨가 무조건 환율 적용 되게 수정 요청 함 
  await scwin.f_ExrateLoading(param1, param2, param3);
  if (ds_ExRate.getRowCount() > 0) {
    ed_rate.setValue(ds_ExRate.getCellData(0, 'code'));
    ed_exrate.setValue(ds_ExRate.getCellData(0, 'name'));
    scwin.exRateCheck = '2';
    scwin.exRate1 = ed_rate.getValue();
    scwin.crc = acb_cucd.getValue();
    scwin.exRate2 = ed_exrate.getValue();
  } else {
    $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_049, ['Ex-Rate']); // @이(가) 존재하지 않습니다. 
    scwin.exRateCheck = '1';
  }
  ;
};

/**
 * @event 
 * @name ed_rate_onchange
 * @description Ex-Rate component의 value가 변경되었을 때 발생
 */
scwin.ed_rate_onchange = function () {
  // for=ed_rate event=onKillFocus()
  if (scwin.exRateCheck == '1') {
    if (ed_exrate.getValue() == '' || ed_exrate.getValue() == '0') {
      ed_exrate.setValue(ed_rate.getValue());
    }
    ;
    scwin.crc = acb_cucd.getValue();
    scwin.exRate1 = ed_rate.getValue();
  }
  ;
};

/**
 * @event 
 * @name ed_exrate_onchange
 * @description US Ex-Rate component의 value가 변경되었을 때 발생
 */
scwin.ed_exrate_onchange = function () {
  // for=ed_exrate event=onKillFocus()
  if (scwin.exRateCheck == '1') {
    scwin.exRate2 = ed_exrate.getValue();
  }
  ;
};

