/**
 * @event 
 * @name gr_BuyingFreightInfo_onafteredit
 * @description Buying) 셀의 편집모드가 종료되어 포커스가 빠져나온 경우에 발생 (oneditend 이벤트 이후 발생)
 * @asis for=gr_BuyingFreightInfo event=OnCloseUp(Row,Colid)
 * @asis for=gr_BuyingFreightInfo event=OnExit(row,colid,olddata)
 */
scwin.gr_BuyingFreightInfo_onafteredit = function (rowIndex, columnIndex, value) {
  let colId = gr_BuyingFreightInfo.getColumnID(columnIndex);
  let oldData = ds_BuyingFreightInfo.getOriginalCellData(rowIndex, colId);
  switch (colId) {
    case 'pchsTyp':
      if (ds_BuyingFreightInfo.getCellData(rowIndex, 'pchsTyp') == '3') {
        gr_BuyingFreightInfo.setColumnReadOnly('sellDeptCd', '');
      } else {
        gr_BuyingFreightInfo.setColumnReadOnly('sellDeptCd', true);
      }
      ;
      break;
    case 'crcCd':
      scwin.f_CurrRateSetting(rowIndex, colId, 'Buying'); // 화율정보에 따른 EX-Rate 가져오기			
      break;
    case 'pchsClntNo':
      //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
      if (!['', oldData].includes(value)) {
        ds_BuyingFreightInfo.setCellData(rowIndex, 'pchsClntNm', '');
        scwin.f_PopUpGrid('BuyingCustomer', rowIndex, 'T', 'F', 'F');
      }
      //Name field 존재시 check.
      //Name Value 가 Blank 일경우 코드값을 Blank 한다.
      else if (value == '') {
        ds_BuyingFreightInfo.setCellData(rowIndex, 'pchsClntNm', '');
        ds_BuyingFreightInfo.setCellData(rowIndex, 'pchsClntNo', '');
      }
      ;
      break;
    case 'fareEngCd':
      if (!['', oldData].includes(value)) {
        ds_BuyingFreightInfo.setCellData(rowIndex, 'fareEngNm', '');
        scwin.f_PopUpGrid('BuyingFreight', rowIndex, 'T', 'F', 'F');
      } else if (value == '') {
        ds_BuyingFreightInfo.setCellData(rowIndex, 'fareEngNm', '');
        ds_BuyingFreightInfo.setCellData(rowIndex, 'fareEngCd', '');
      }
      ;
      break;
    case 'sellDeptCd':
      if (!['', oldData].includes(value)) {
        ds_BuyingFreightInfo.setCellData(rowIndex, 'sellDeptNm', '');
        scwin.f_PopUpGrid('BuyingInnerDept', rowIndex, 'T', 'F', 'F');
      } else if (value == '') {
        ds_BuyingFreightInfo.setCellData(rowIndex, 'sellDeptNm', '');
        ds_BuyingFreightInfo.setCellData(rowIndex, 'sellDeptCd', '');
      }
      ;
      break;
    default:
      break;
  }
  ;
  if (value != oldData) {
    scwin.f_PkgWegihtSetting(rowIndex, colId, 'Buying');
    if (colId == 'fareEngCd') {
      //ATC, ATCV 자동 계산 부분 (Gweight *35 +2000원) 소수 점 버림 처리 
      if (value != oldData) {
        if (['ATC', 'ATCV'].includes(value)) {
          ds_BuyingFreightInfo.setCellData(rowIndex, 'crcCd', 'KRW');
          ds_BuyingFreightInfo.setCellData(rowIndex, 'exRate', 1);
          ds_BuyingFreightInfo.setCellData(rowIndex, 'pchsUpr', 1);
          ds_BuyingFreightInfo.setCellData(rowIndex, 'chgWt', dma_HouseFreightInfo.get('mftwht'));
          ds_BuyingFreightInfo.setCellData(rowIndex, 'pchsAmt', Math.round(ds_BuyingFreightInfo.getCellData(rowIndex, 'chgWt') * 35 + 2000 - 0.5));
          if (ds_BuyingFreightInfo.getCellData(rowIndex, colId) == 'ATCV') {
            //buying 부가세 소수점 버림 
            ds_BuyingFreightInfo.setCellData(rowIndex, 'vat', Math.round(ds_BuyingFreightInfo.getCellData(rowIndex, 'pchsAmt') * 0.1 - 0.5));
          }
        }
      }
    }
    scwin.f_RateAmount(rowIndex, colId, 'Buying', oldData);
  }
  ;
};

/**
 * @event 
 * @name gr_SellingFreightInfo_onafteredit
 * @description Selling) 셀의 편집모드가 종료되어 포커스가 빠져나온 경우에 발생 (oneditend 이벤트 이후 발생)
 * @asis for=gr_SellingFreightInfo event=OnCloseUp(Row,Colid)
 */
scwin.gr_SellingFreightInfo_onafteredit = async function (rowIndex, columnIndex, value) {
  let colId = gr_SellingFreightInfo.getColumnID(columnIndex);
  let oldData = ds_SellingFreightInfo.getOriginalCellData(rowIndex, colId);
  switch (colId) {
    case 'crcCd':
      scwin.f_CurrRateSetting(rowIndex, colId, 'Selling'); // 화율정보에 따른 EX-Rate 가져오기			
      break;
    case 'bilgClntNo':
      //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
      if (!['', oldData].includes(value)) {
        ds_SellingFreightInfo.setCellData(rowIndex, 'bilgClntNm', '');
        await scwin.f_PopUpGrid('SellingCustomer', rowIndex, 'T', 'F', 'F');
      }
      //Name field 존재시 check.
      //Name Value 가 Blank 일경우 코드값을 Blank 한다.
      else if (value == '') {
        ds_SellingFreightInfo.setCellData(rowIndex, 'bilgClntNm', '');
        ds_SellingFreightInfo.setCellData(rowIndex, 'bilgClntNo', '');
      }
      ;
      break;
    case 'fareEngCd':
      if (!['', oldData].includes(value)) {
        await scwin.f_PopUpGrid('SellingFreight', rowIndex, 'T', 'F', 'F');
        ds_SellingFreightInfo.setCellData(rowIndex, 'fareEngNm', '');
      } else if (value == '') {
        ds_SellingFreightInfo.setCellData(rowIndex, 'fareEngNm', '');
        ds_SellingFreightInfo.setCellData(rowIndex, 'fareEngCd', '');
      }
      ;
      break;
  }
  ;
  if (value != oldData) {
    scwin.f_PkgWegihtSetting(rowIndex, colId, 'Selling');
    if (colId == 'fareEngCd') {
      //ATC, ATCV 자동 계산 부분 (Gweight *35 +2000원) 소수 점 버림 처리 
      if (value != oldData && ['ATC', 'ATCV'].includes(value)) {
        let mftwhtVal = dma_HouseFreightInfo.get('mftwht');
        ds_SellingFreightInfo.setCellData(rowIndex, 'crcCd', 'KRW');
        ds_SellingFreightInfo.setCellData(rowIndex, 'exRate', 1);
        ds_SellingFreightInfo.setCellData(rowIndex, 'sellUpr', 1);
        ds_SellingFreightInfo.setCellData(rowIndex, 'grossWt', mftwhtVal);
        ds_SellingFreightInfo.setCellData(rowIndex, 'sellAmt', Math.round(ds_SellingFreightInfo.getCellData(rowIndex, 'grossWt') * 35 + 2000 - 0.5));
        if (value == 'ATCV') {
          ds_SellingFreightInfo.setCellData(rowIndex, 'vat', Math.round(ds_SellingFreightInfo.getCellData(rowIndex, 'pchsAmt') * 0.1));
        }
        ;
      }
      ;
    }
    ;
    scwin.f_RateAmount(rowIndex, colId, 'Selling', oldData);
  }
  ;
};

